1	import { describe, it, expect } from "vitest";
2	import { scalePixelArt } from "./pixel-art-scaler.js";
3	
4	describe("Pixel Art Scaler", () => {
5	  it("should return empty array for empty input", () => {
6	    expect(scalePixelArt([], 2)).toEqual([]);
7	  });
8	  it("should return exact copy for scale factor of 1 with single pixel", () => {
9	    expect(scalePixelArt([[255]], 1)).toEqual([[255]]);
10	  });
11	  it("should return exact copy for scale factor of 1 with single row", () => {
12	    expect(scalePixelArt([[255, 0, 128]], 1)).toEqual([[255, 0, 128]]);
13	  });
14	  it("should return exact copy for scale factor of 1 with multiple rows", () => {
15	    expect(scalePixelArt([[255, 0], [128, 64]], 1)).toEqual([[255, 0], [128, 64]]);
16	  });
17	  it("should replicate single pixel horizontally by scale factor", () => {
18	    expect(scalePixelArt([[255]], 2)).toEqual([[255, 255], [255, 255]]);
19	  });
20	  it("should replicate single pixel both horizontally and vertically by scale factor", () => {
21	    expect(scalePixelArt([[255]], 2)).toEqual([[255, 255], [255, 255]]);
22	  });
23	  it("should replicate each pixel in a single row horizontally by scale factor", () => {
24	    expect(scalePixelArt([[255, 0]], 2)).toEqual([[255, 255, 0, 0], [255, 255, 0, 0]]);
25	  });
26	  it("should replicate each row vertically by scale factor", () => {
27	    expect(scalePixelArt([[255, 0], [128, 64]], 2)).toEqual([[255, 255, 0, 0], [255, 255, 0, 0], [128, 128, 64, 64], [128, 128, 64, 64]]);
28	  });
29	  it.todo("should scale a multi-row multi-column image by scale factor");
30	});
31

1	const scaleRowHorizontally = (row: number[], scaleFactor: number): number[] =>
2	  row.flatMap(pixel => Array(scaleFactor).fill(pixel));
3	
4	export function scalePixelArt(image: number[][], scaleFactor: number): number[][] {
5	  return image.flatMap(row =>
6	    Array(scaleFactor).fill(scaleRowHorizontally(row, scaleFactor))
7	  );
8	}
